/// <summary>
/// <c>ETGSPAINInventTransApplicationMovement</c> table is used to store the applied movement records.
/// </summary>
public class ETGSPAINInventTransApplicationMovement extends common
{
}

Method.Source:
/// <summary>
/// Searches for Applied Movement record.
/// </summary>
/// <param name="_inventTransApplicationFrom">Original reference of InventTransApplication.</param>
/// <param name="_inventTransApplicationTo">Destination reference of InventTransApplication.</param>
/// <param name="_forUpdate">Whether to update.</param>
/// <returns>Returns <c>ETGSPAINInventTransApplicationMovement</c> record.</returns>
public static ETGSPAINInventTransApplicationMovement find(
    RefRecId   _inventTransApplicationFrom,
    RefRecId   _inventTransApplicationTo,
    boolean    _forUpdate = false)
{
    ETGSPAINInventTransApplicationMovement ETGSPAINInventTransApplicationMovement;

    ETGSPAINInventTransApplicationMovement.selectForUpdate(_forUpdate);

    select firstonly ETGSPAINInventTransApplicationMovement
        where ETGSPAINInventTransApplicationMovement.InventTransApplicationFromRefRecId == _inventTransApplicationFrom
            && ETGSPAINInventTransApplicationMovement.InventTransApplicationToRefRecId  == _inventTransApplicationTo;

    return ETGSPAINInventTransApplicationMovement;
}

/// <summary>
/// Method to check if the record exists.
/// </summary>
/// <param name="_inventTransApplicationFrom">Original reference of InventTransApplication.</param>
/// <param name="_inventTransApplicationTo">Destination reference of InventTransApplication.</param>
/// <returns>Returns value if the record exists.</returns>
public static boolean exist(
    RefRecId _inventTransApplicationFrom,
    RefRecId _inventTransApplicationTo)
{
    return _inventTransApplicationFrom && _inventTransApplicationTo && (select firstonly RecId
                                                                        from ETGSPAINInventTransApplicationMovement
                                                                        where ETGSPAINInventTransApplicationMovement.InventTransApplicationFromRefRecId == _inventTransApplicationFrom
                                                                            && ETGSPAINInventTransApplicationMovement.InventTransApplicationToRefRecId  == _inventTransApplicationTo).RecId != 0;
}
